from gdpy.exceptions import (
    GDError,
    NotFoundError,
    InvalidRequestError,
)

with Client() as client:
    try:
        user = client.get_user(account_id=999999999)
    except NotFoundError:
        print("User not found")
    except InvalidRequestError:
        print("Rate limited or invalid request")
    except GDError as e:
        print(f"Error: {e}")
