SynchronousAsynchronous <pre><code>from gdpy import Client
from gdpy.exceptions import (
    UsernameTakenError,
    EmailTakenError,
    PasswordTooShortError,
    UsernameTooShortError,
)

with Client() as client:
    try:
        client.register("user", "pass", "email@test.com")
    except UsernameTakenError:
        print("Username already exists")
    except EmailTakenError:
        print("Email already registered")
    except PasswordTooShortError:
        print("Password must be at least 6 characters")
    except UsernameTooShortError:
        print("Username must be at least 3 characters")
</code></pre> <pre><code>import asyncio
from gdpy import AsyncClient
from gdpy.exceptions import (
    UsernameTakenError,
    EmailTakenError,
    PasswordTooShortError,
    UsernameTooShortError,
)

async def main():
    async with AsyncClient() as client:
        try:
            await client.register("user", "pass", "email@test.com")
        except UsernameTakenError:
            print("Username already exists")

asyncio.run(main())
